    display: grid; grid-template-columns: 1fr 1fr; gap: 8px;
    margin-bottom: 20px;
  }
  .method {
    border: 1px solid var(--line);
    border-radius: 10px;
    padding: 14px 12px;
    cursor: pointer;
    background: var(--bg-elev);
    text-align: left;
    font: inherit; color: inherit;
    transition: border-color .15s;
    position: relative;
  }
  .method:hover { border-color: var(--line-strong); }
  .method.active {
    border-color: var(--teal);
    background: var(--teal-tint);
  }
  .method .icon {
    width: 28px; height: 28px;
    border-radius: 7px;
    background: var(--bg-sunken);
    color: var(--teal-2);
    display: grid; place-items: center;
    margin-bottom: 8px;
  }
  .method.active .icon { background: var(--teal); color: #fff; }
  .method .lbl { font-size: 12.5px; font-weight: 600; }
  .method .sub { font-size: 11px; color: var(--ink-3); margin-top: 2px; }

  .field { margin-bottom: 14px; }
  .field label {
    display: block;
    font-size: 11.5px; font-weight: 600;
    color: var(--ink-2); margin-bottom: 6px;
  }
  .field input {
    width: 100%; height: 40px;
    padding: 0 12px;
    border: 1px solid var(--line-strong);
    border-radius: 8px;
    font: inherit; font-size: 13.5px;
    background: var(--bg-elev);
    color: var(--ink);
    outline: none;
  }
  .field input:focus { border-color: var(--teal); box-shadow: 0 0 0 3px var(--teal-soft); }

  .row { display: flex; align-items: center; justify-content: space-between; margin: 6px 0 18px; }
  .check { display: flex; align-items: center; gap: 7px; font-size: 12.5px; color: var(--ink-2); cursor: pointer; }
  .check input { accent-color: var(--teal); }
  .row a { color: var(--teal-2); text-decoration: none; font-size: 12.5px; }
  .row a:hover { text-decoration: underline; }

  .btn-signin {
    width: 100%; height: 44px;
    border: 0; border-radius: 9px;
    background: var(--teal);
    color: #fff;
    font: inherit; font-size: 14px; font-weight: 600;
    cursor: pointer;
    display: inline-flex; align-items: center; justify-content: center; gap: 8px;
  }
  .btn-signin:hover { background: var(--teal-2); }

  .hba-card {
    margin-top: 18px;
    padding: 14px;
    background: var(--bg-sunken);
    border-radius: 10px;
    display: flex; gap: 12px; align-items: center;
    font-size: 12px;
    color: var(--ink-2);
  }
  .hba-card .hba-icon {
    width: 36px; height: 36px;
    border-radius: 7px;
    background: var(--bg-elev);
    border: 1px solid var(--line);
    display: grid; place-items: center;
    color: var(--teal-2);
    flex-shrink: 0;
  }
  .hba-card strong { color: var(--ink); }

  .footer-meta {
    position: absolute; bottom: 24px; left: 0; right: 0;
    text-align: center;
    font-size: 11.5px; color: var(--ink-4);
  }
  .footer-meta a { color: var(--ink-3); margin: 0 8px; text-decoration: none; }

  /* Welcome (post-login) overlay */
  .welcome-overlay {
    position: fixed; inset: 0;
    background: linear-gradient(180deg, #0c1e1e 0%, #0a1418 100%);
    z-index: 50;
    display: grid; place-items: center;
    color: #e7edf3;
    opacity: 0;
    pointer-events: none;
    transition: opacity .4s ease;
  }
  .welcome-overlay.show { opacity: 1; pointer-events: auto; }
  .welcome-inner {
    text-align: center;
    max-width: 560px;
    padding: 40px;
    position: relative;
  }
  .welcome-inner::before {
    /* radiant glow */
    content: ""; position: absolute; inset: -120px;
    background: radial-gradient(circle, rgba(56,189,189,.18), transparent 60%);
    pointer-events: none;
  }
  .welcome-pet {
    width: 120px; height: 120px;
    border-radius: 50%;
    margin: 0 auto 24px;
    background: radial-gradient(circle at 35% 30%, #66d4d4, #0d8a8a 65%, #064848 100%);
    box-shadow:
      0 0 0 8px rgba(56,189,189,.12),
      0 0 0 16px rgba(56,189,189,.06),
      0 24px 60px rgba(56,189,189,.45);
    position: relative;
    animation: pet-float 3.4s ease-in-out infinite;
  }
  @keyframes pet-float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-8px); }
  }
  .welcome-pet::before, .welcome-pet::after {
    /* eyes */
    content: ""; position: absolute;
    width: 14px; height: 18px; border-radius: 50%;
    background: #0a1418; top: 42%;
    animation: blink 4.2s infinite;
  }
  .welcome-pet::before { left: 30%; }
  .welcome-pet::after { right: 30%; }
  @keyframes blink {
    0%, 92%, 100% { transform: scaleY(1); }
    95% { transform: scaleY(0.05); }
  }
  .welcome-greet-eyebrow {
    font-size: 12px; font-weight: 600; letter-spacing: .14em;
    text-transform: uppercase; color: #38bdbd;
    margin-bottom: 14px;
  }
  .welcome-greet h1 {
    font-size: 38px; font-weight: 500; letter-spacing: -0.02em;
    margin: 0 0 8px; line-height: 1.2;
  }
  .welcome-greet h1 .name { color: #66d4d4; font-weight: 600; }
  .welcome-greet .companion-says {
    font-family: "Amiri", serif;
    font-size: 18px; font-style: italic;
    color: #aab7c5; margin: 18px 0 24px; line-height: 1.5;
  }
  .welcome-greet .companion-says .who {
    display: block;
    font-family: "Inter", sans-serif;
    font-size: 11px; color: #7c8a9c; font-style: normal;
    letter-spacing: .08em; text-transform: uppercase; margin-top: 6px;
  }
  .welcome-progress {
    margin-top: 28px;
    width: 280px; margin-left: auto; margin-right: auto;
    height: 3px; border-radius: 2px;
    background: rgba(56,189,189,.18);
    overflow: hidden;
  }
  .welcome-progress > i {
    display: block; height: 100%;
    background: #38bdbd;
    width: 0;
    animation: fill 2.0s ease-out forwards;
  }
  @keyframes fill { from { width: 0; } to { width: 100%; } }
  .welcome-cta {
    margin-top: 24px;
    display: inline-flex; align-items: center; gap: 8px;
    padding: 0 18px; height: 38px;
    background: rgba(56,189,189,.16);
    border: 1px solid rgba(56,189,189,.4);
    color: #66d4d4;
    border-radius: 8px; cursor: pointer;
    font: inherit; font-size: 13px; font-weight: 500;
  }
  .welcome-cta:hover { background: rgba(56,189,189,.24); }

  @media (max-width: 880px) {
    .welcome-stage { grid-template-columns: 1fr; }
    .brand-panel { display: none; }
  }
</style>
</head>
<body>
<div class="welcome-stage">
  <!-- LEFT -->
  <section class="brand-panel">
    <div class="brand-mark">
      <div class="logo">M</div>
      <div>Medion <em>KIS</em></div>
    </div>

    <div class="hero">
      <div class="eyebrow">Klinikinformationssystem · v5.4.7</div>
      <h1>
        Sorgfältig dokumentieren.<br/>
        Mit <span class="accent">Hakîm</span> an Ihrer Seite.
      </h1>
      <p>
        Medion KIS verbindet Patientenakte, Stationsalltag und Dokumentation in einer ruhigen,
        klinisch klaren Umgebung. Ihr KI-Begleiter — benannt nach den großen Gelehrten der
        islamischen Goldmedizin — hört mit, fasst zusammen und schlägt SOAP-Texte vor.
      </p>
      <div class="hadith">
        „Wer einen einzigen Menschen am Leben erhält, dem wird angerechnet, als hätte er allen Menschen das Leben geschenkt.“
        <span class="src">— Sure 5:32</span>
      </div>
    </div>

    <div class="ti-strip">
      <span class="pill"><span class="dot"></span>TI Online</span>
      <span class="pill"><span class="dot"></span>KIM aktiv</span>
      <span class="pill"><span class="dot"></span>Konnektor PT-3</span>
      <span class="pill"><span class="dot"></span>VSDM bereit</span>
      <span class="pill" style="margin-left:auto;color:#5a6675">Klinikum München · 5. Stock</span>
    </div>
  </section>

  <!-- RIGHT -->
  <section class="signin-panel">
    <div class="signin-card">
      <div class="greeting">Willkommen zurück</div>
      <h2 id="greet-line">Guten Morgen, Frau Dr. Weber</h2>
      <div class="meta">Bitte melden Sie sich an, um Ihre Schicht zu beginnen. <br/>Heute, 26. April 2026 · 07:42 Uhr</div>

      <div class="login-method">
        <button class="method active" id="m-hba">
          <div class="icon">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="6" width="18" height="13" rx="2"/><path d="M7 10h6M7 13h4M16 14h2"/></svg>
          </div>
          <div class="lbl">eHBA-Karte</div>
          <div class="sub">Heilberufsausweis</div>
        </button>
        <button class="method" id="m-pwd">
          <div class="icon">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="4" y="11" width="16" height="10" rx="2"/><path d="M8 11V7a4 4 0 0 1 8 0v4"/></svg>
          </div>
          <div class="lbl">Benutzer & PIN</div>
          <div class="sub">Standard</div>
        </button>
      </div>

      <div class="field">
        <label>Benutzerkennung (LANR)</label>
        <input type="text" value="123456789" id="lanr"/>
      </div>
      <div class="field">
        <label>HBA-PIN</label>
        <input type="password" value="••••••" id="pin"/>
      </div>

      <div class="row">
        <label class="check"><input type="checkbox" checked/> Auf diesem Gerät merken (8 Std.)</label>
        <a href="#">PIN vergessen?</a>
      </div>

      <button class="btn-signin" id="signin-btn">
        Anmelden & Schicht beginnen
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2"><path d="M5 12h14M13 6l6 6-6 6"/></svg>
      </button>

      <div class="hba-card">
        <div class="hba-icon">
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 2 4 6v6c0 5 3.5 9 8 10 4.5-1 8-5 8-10V6l-8-4z"/></svg>
        </div>
        <div>
          eHBA erkannt: <strong>Dr. med. Maria Weber</strong> · Innere Medizin<br/>
          Konnektor: <span class="mono">PT-3 · 192.168.4.12</span> · TI online · KIM aktiv
        </div>
      </div>
    </div>

    <div class="footer-meta">
      <a href="#">Datenschutz</a>·<a href="#">Impressum</a>·<a href="#">Hilfe</a>·<a href="#">v5.4.7 (Build 26041)</a>
    </div>
  </section>
</div>

<!-- post-login welcome (avatar greeting) -->
<div class="welcome-overlay" id="welcome">
  <div class="welcome-inner">
    <div class="welcome-pet"></div>
    <div class="welcome-greet">
      <div class="welcome-greet-eyebrow">As-salāmu ʿalaykum, Frau Dr. Weber</div>
      <h1>Willkommen zurück, <span class="name">Dr. Weber</span></h1>
      <div class="companion-says">
        „Heute begleite ich Sie auf Visite. <br/>Die SOAP-Dokumentation für 8 Patientinnen wartet bereits — beginnen wir bei Frau Schmidt, Zimmer 412.“
        <span class="who">— Hakîm, Ihr Begleiter</span>
      </div>
      <div class="welcome-progress"><i></i></div>
      <button class="welcome-cta" id="goto-soap">
        Direkt zu SOAP-Verlauf
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2"><path d="M5 12h14M13 6l6 6-6 6"/></svg>
      </button>
    </div>
  </div>
</div>

<script>
  // method toggle
  document.getElementById("m-hba").addEventListener("click", () => {
    document.getElementById("m-hba").classList.add("active");
    document.getElementById("m-pwd").classList.remove("active");
  });
  document.getElementById("m-pwd").addEventListener("click", () => {
    document.getElementById("m-pwd").classList.add("active");
    document.getElementById("m-hba").classList.remove("active");
  });

  function goToKis() {
    location.href = "Medion KIS.html#soap";
  }

  document.getElementById("signin-btn").addEventListener("click", () => {
    document.getElementById("welcome").classList.add("show");
    setTimeout(goToKis, 2200);
  });
  document.getElementById("goto-soap").addEventListener("click", goToKis);

  // greet by time
  const h = new Date().getHours();
  const greet = h < 5 ? "Gute Nacht" : h < 11 ? "Guten Morgen" : h < 17 ? "Guten Tag" : "Guten Abend";
  document.getElementById("greet-line").textContent = `${greet}, Frau Dr. Weber`;
</script>
</body>
</html>

